"use client";
import React, { useState } from "react";
import { projects } from "../data/projects";
import { AnimatePresence, motion } from "framer-motion";
import Image from "next/image";
import LinkArrow from "./LinkArrow";

const Archive = () => {
  const [openProjectId, setOpenProjectId] = useState<number | null>(null);

  const handleToggleProject = (projectId: number) => {
    setOpenProjectId((current) => (current === projectId ? null : projectId));
  };

  return (
    <section className="section-base relative z-10 flex flex-col gap-12 md:gap-16">
      <div className="flex flex-col gap-4">
        <div className="h-px w-full bg-foreground/10" />
        <div className="flex justify-between lg:grid gap-4 lg:grid-cols-3 lg:gap-8">
          <h2 className="subtitle-small">Archive</h2>
          <span className="subtitle-small hidden lg:block">Past Work</span>
          <span className="subtitle-small sm:justify-self-end">
            {projects.length < 10
              ? `(0${projects.length})`
              : `(${projects.length})`}
          </span>
        </div>
      </div>
      <div className="grid grid-cols-1 gap-6 md:grid-cols-2 lg:grid-cols-3 lg:gap-8">
        <p className="lg:col-start-2 lg:max-w-sm">
          Here you can find all my projects, sorted by year. Click on a project
          to see more details. For more details, check out my Instagram and
          Linkedin
        </p>
        <p className="max-w-sm">
          Some projects are not yet public, but you can still see the details
          and visuals.
        </p>
      </div>
      <div className="flex flex-col gap-0">
        <div className="hidden grid-cols-6 gap-8 border-b border-foreground/10 pb-8 tracking-wider lg:grid">
          <span className="col-span-2 subtitle-small text-xs!">Client</span>
          <span className="subtitle-small text-xs!">Year</span>
          <span className="subtitle-small text-xs!">Industry</span>
          <span className="subtitle-small text-xs!">Services</span>
          <span className="subtitle-small text-xs!">Location</span>
        </div>
        {projects.map((project) => (
          <ProjectCard
            key={project.id}
            id={project.id}
            photos={project.photos}
            title={project.title}
            year={project.year}
            type={project.type}
            link={project.link}
            tools={project.tools}
            description={project.description}
            industry={project.industry}
            location={project.location}
            isOpen={openProjectId === project.id}
            onToggle={() => handleToggleProject(project.id)}
          />
        ))}
      </div>
    </section>
  );
};

export default Archive;

export function ProjectCard({
  id,
  title,
  year,
  type,
  link,
  tools,
  description,
  location,
  isOpen,
  industry,
  onToggle,
  photos,
}: {
  id: number;
  title: string;
  year: number;
  type: string;
  tools: string[];
  photos?: string[];
  link?: string;
  description: string[];
  industry: string;
  location: string;
  isOpen: boolean;
  onToggle: () => void;
}) {
  return (
    <div className="flex flex-col border-b border-foreground/10 ">
      <motion.button
        type="button"
        onClick={onToggle}
        className="relative grid cursor-pointer grid-cols-1 gap-4 py-6 text-left sm:gap-6 lg:grid-cols-6 lg:gap-8 lg:py-8"
        initial="rest"
        animate={isOpen ? "open" : "rest"}
        whileHover="hover"
        variants={{
          rest: { opacity: 0.5 },
          hover: { opacity: 1 },
          open: { opacity: 1 },
        }}
        transition={{ duration: 0.9, ease: [0.22, 1, 0.36, 1] }}
        aria-expanded={isOpen}
        aria-controls={`project-details-${id}`}
      >
        <div className="relative overflow-hidden lg:col-span-2">
          <div className="pointer-events-none absolute inset-y-0 left-0 flex items-center">
            <motion.div
              variants={{
                rest: { x: 0 },
                hover: { x: "100%" },
                open: { x: 0 },
              }}
              className="-translate-x-full"
              transition={{ duration: 0.9, ease: [0.22, 1, 0.36, 1] }}
            >
              <svg
                xmlns="http://www.w3.org/2000/svg"
                fill="none"
                viewBox="0 0 24 24"
                strokeWidth={3}
                stroke="currentColor"
                className="size-6"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  d="M13.5 4.5 21 12m0 0-7.5 7.5M21 12H3"
                />
              </svg>
            </motion.div>
          </div>
          <motion.h3
            className="z-10 max-w-full text-2xl font-medium tracking-wide sm:max-w-3xl sm:text-3xl"
            variants={{
              rest: { marginLeft: 0 },
              hover: { marginLeft: "2rem" },
              open: { marginLeft: 0 },
            }}
            transition={{ duration: 0.9, ease: [0.22, 1, 0.36, 1] }}
          >
            {title}
          </motion.h3>
        </div>
        <div className="grid grid-cols-2 gap-x-4 gap-y-2 text-sm font-medium lg:contents">
          <span className="z-10 lg:self-center">{year}</span>
          <span className="z-10 lg:self-center">{industry}</span>
          <span className="z-10 lg:self-center">{type}</span>
          <span className="z-10 min-w-0 break-words lg:self-center">
            {location}
          </span>
        </div>
      </motion.button>
      <AnimatePresence initial={false}>
        {isOpen && (
          <motion.div
            id={`project-details-${id}`}
            className="overflow-hidden"
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: "auto", opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{
              height: { duration: 0.62, ease: [0.22, 1, 0.36, 1] },
              opacity: { duration: 0.62, ease: "easeOut" },
            }}
          >
            <div className="flex flex-col gap-6 pt-4 pb-6 sm:gap-8 sm:pb-8">
              <div className="grid grid-cols-1 gap-6 md:grid-cols-2 lg:grid-cols-3 lg:gap-8">
                {description.map((item, index) => (
                  <p key={index} className="max-w-none">
                    {item}
                  </p>
                ))}
              </div>

              {link && (
                <LinkArrow className="opacity-60" href={link}>
                  Visit Website
                </LinkArrow>
              )}
              <div className="flex flex-wrap gap-2">
                {tools.map((tool, index) => (
                  <span
                    key={index}
                    className="text-xs opacity-60 uppercase font-medium self-center tracking-wider py-1 px-2 border border-foreground/30 rounded-full"
                  >
                    {tool}
                  </span>
                ))}
              </div>
            </div>
            <div className="grid grid-cols-1 gap-3 sm:grid-cols-2 lg:grid-cols-3 lg:gap-2">
              {photos &&
                photos.map((photo, index) => (
                  <ProjectPhoto key={index} src={photo} />
                ))}
            </div>
            <div className="w-full h-8" />
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

function ProjectPhoto({ src }: { src: string }) {
  return (
    <div className="relative flex aspect-4/3 w-full items-center justify-center overflow-hidden rounded-sm bg-[#313131] p-2 sm:p-4">
      <div className="relative h-full w-full">
        <Image
          className="z-10 rounded-sm object-contain duration-300 ease-out"
          src={src}
          alt={`Project photo ${src}`}
          fill
          sizes="(max-width: 640px) 100vw, (max-width: 1024px) 50vw, 33vw"
        />
      </div>
    </div>
  );
}

function ArrowRightUp() {
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      fill="none"
      viewBox="0 0 24 24"
      strokeWidth={2.5}
      stroke="currentColor"
      style={{
        height: "1em",
        width: "auto",
        display: "inline-block",
        verticalAlign: "middle",
      }}
      className="align-middle"
    >
      <path
        strokeLinecap="round"
        strokeLinejoin="round"
        d="m4.5 19.5 15-15m0 0H8.25m11.25 0v11.25"
      />
    </svg>
  );
}

